import unittest
from unittest.mock import Mock, patch
from app.models.agent import SPICMacayConversationalAgent

class TestConversationalAgent(unittest.TestCase):
    
    def setUp(self):
        """Set up test fixtures"""
        self.db_validator = Mock()
        self.agent = SPICMacayConversationalAgent(
            api_key='test-key',
            model='gpt-3.5-turbo',
            db_validator=self.db_validator
        )
    
    def test_agent_initialization(self):
        """Test agent initializes correctly"""
        self.assertIsNotNone(self.agent)
        self.assertEqual(len(self.agent.conversation_history), 0)
        self.assertEqual(len(self.agent.collected_data), 0)
    
    def test_greeting_message(self):
        """Test greeting message is generated"""
        greeting = self.agent.get_greeting()
        self.assertIsInstance(greeting, str)
        self.assertIn('SPIC MACAY', greeting)
    
    def test_reset_conversation(self):
        """Test conversation reset"""
        # Add some data
        self.agent.conversation_history.append({"role": "user", "content": "test"})
        self.agent.collected_data = {"test": "data"}
        
        # Reset
        self.agent.reset()
        
        # Verify reset
        self.assertEqual(len(self.agent.conversation_history), 0)
        self.assertEqual(len(self.agent.collected_data), 0)
    
    @patch('openai.chat.completions.create')
    def test_chat_with_error_handling(self, mock_openai):
        """Test chat handles errors gracefully"""
        # Simulate OpenAI error
        mock_openai.side_effect = Exception("API Error")
        
        response = self.agent.chat("Hello")
        
        self.assertFalse(response.get('success'))
        self.assertIn('error', response)

